SELECT * FROM sys_menu WHERE del_flag = '0'

    AND menu_name LIKE CONCAT('%', #{menuName}, '%')


    AND visible = #{visible}


    AND status = #{status}

ORDER BY parent_id, order_num

SELECT m.id FROM sys_menu m
LEFT JOIN sys_role_menu rm ON m.id = rm.menu_id
WHERE rm.role_id = #{roleId}

