    is_frame, is_cache, menu_type, visible, status, perms, icon,
    create_by, create_time, remark
) VALUES (
    #{menuName}, #{parentId}, #{orderNum}, #{path}, #{component}, #{query},
    #{isFrame}, #{isCache}, #{menuType}, #{visible}, #{status}, #{perms}, #{icon},
    #{createBy}, NOW(), #{remark}
