mapper.update:
UPDATE sys_menu SET menu_name = #{menuName}, parent_id = #{parentId}, order_num = #{orderNum}, path = #{path}, component = #{component}, query = #{query}, is_frame = #{isFrame}, is_cache = #{isCache}, menu_type = #{menuType}, visible = #{visible}, status = #{status}, perms = #{perms}, icon = #{icon}, update_by = #{updateBy}, update_time = NOW()
, remark = #{remark}
WHERE id = #{id}
